//! RTMP protocol encoding — handshake + AMF0 commands + chunk-stream framing.
//!
//! This is the sovereign RTMP wire, the half native ffmpeg's `-f flv rtmp://…`
//! does today. It is PURE byte construction (no I/O): a swerve sliver imports this
//! to do the raw-TCP dance (connect → send handshake → read S0/S1/S2 → connect →
//! createStream → publish → stream FLV audio/video as RTMP messages). The media
//! payloads come from [`crate::flv`]'s tag bodies. Pure std, wasm32-safe.

/// RTMP handshake C0+C1: version byte (0x03) followed by a 1536-byte C1
/// (4-byte time, 4 zero bytes, 1528 bytes of payload). Returns the bytes to send.
pub fn handshake_c0c1(timestamp: u32) -> Vec<u8> {
    let mut b = Vec::with_capacity(1 + 1536);
    b.push(0x03); // C0: RTMP version 3
    b.extend_from_slice(&timestamp.to_be_bytes());
    b.extend_from_slice(&[0u8; 4]); // zero
    // 1528 bytes of deterministic payload (a real client may randomize).
    let mut x = 0x1234_5678u32;
    for _ in 0..1528 {
        x = x.wrapping_mul(1_664_525).wrapping_add(1_013_904_223);
        b.push((x >> 24) as u8);
    }
    b
}

/// Build C2 from the peer's S1 (echo it back, as the simple handshake allows).
pub fn handshake_c2(s1: &[u8]) -> Vec<u8> {
    let mut c2 = vec![0u8; 1536];
    let n = s1.len().min(1536);
    c2[..n].copy_from_slice(&s1[..n]);
    c2
}

// ---------------------------------------------------------------- AMF0 -------

pub fn amf0_number(b: &mut Vec<u8>, n: f64) {
    b.push(0x00); // number marker
    b.extend_from_slice(&n.to_be_bytes());
}
pub fn amf0_bool(b: &mut Vec<u8>, v: bool) {
    b.push(0x01);
    b.push(u8::from(v));
}
pub fn amf0_string(b: &mut Vec<u8>, s: &str) {
    b.push(0x02); // string marker
    b.extend_from_slice(&(s.len() as u16).to_be_bytes());
    b.extend_from_slice(s.as_bytes());
}
pub fn amf0_null(b: &mut Vec<u8>) {
    b.push(0x05); // null marker
}
fn amf0_key(b: &mut Vec<u8>, k: &str) {
    b.extend_from_slice(&(k.len() as u16).to_be_bytes());
    b.extend_from_slice(k.as_bytes());
}
fn amf0_object_end(b: &mut Vec<u8>) {
    b.extend_from_slice(&[0x00, 0x00, 0x09]);
}

/// The `connect` command (AMF0): `"connect"`, transaction id 1, command object.
pub fn amf0_connect(app: &str, tc_url: &str) -> Vec<u8> {
    let mut b = Vec::new();
    amf0_string(&mut b, "connect");
    amf0_number(&mut b, 1.0);
    b.push(0x03); // object marker
    amf0_key(&mut b, "app");
    amf0_string(&mut b, app);
    amf0_key(&mut b, "type");
    amf0_string(&mut b, "nonprivate");
    amf0_key(&mut b, "flashVer");
    amf0_string(&mut b, "FMLE/3.0 (sovereign frffmpeg)");
    amf0_key(&mut b, "tcUrl");
    amf0_string(&mut b, tc_url);
    amf0_object_end(&mut b);
    b
}

/// `releaseStream`/`FCPublish`-style single-string command (used before publish).
pub fn amf0_string_command(cmd: &str, txn: f64, arg: &str) -> Vec<u8> {
    let mut b = Vec::new();
    amf0_string(&mut b, cmd);
    amf0_number(&mut b, txn);
    amf0_null(&mut b);
    amf0_string(&mut b, arg);
    b
}

/// `createStream` command.
pub fn amf0_create_stream(txn: f64) -> Vec<u8> {
    let mut b = Vec::new();
    amf0_string(&mut b, "createStream");
    amf0_number(&mut b, txn);
    amf0_null(&mut b);
    b
}

/// `publish` command: the stream key, published as `"live"`.
pub fn amf0_publish(txn: f64, stream_key: &str) -> Vec<u8> {
    let mut b = Vec::new();
    amf0_string(&mut b, "publish");
    amf0_number(&mut b, txn);
    amf0_null(&mut b);
    amf0_string(&mut b, stream_key);
    amf0_string(&mut b, "live");
    b
}

// ---------------------------------------------------------- chunk stream -----

/// A Set Chunk Size control message (type 1 on chunk stream 2) — raise the chunk
/// size from the 128-byte default so large video frames need fewer continuations.
pub fn set_chunk_size(size: u32) -> Vec<u8> {
    chunk_message(2, 0, 0x01, 0, &(size & 0x7FFF_FFFF).to_be_bytes(), 128)
}

/// Frame a full RTMP message into the chunk stream: a type-0 message header on the
/// first chunk (timestamp, length, type, **little-endian** message stream id),
/// then type-3 continuation headers for each subsequent `chunk_size` slice.
///
/// `csid` must be 2..=63 (this encoder uses the 1-byte basic header form).
pub fn chunk_message(
    csid: u8,
    timestamp: u32,
    msg_type: u8,
    msg_stream_id: u32,
    payload: &[u8],
    chunk_size: usize,
) -> Vec<u8> {
    let mut out = Vec::new();
    // First chunk basic header: fmt = 0 (top two bits), csid in low six.
    out.push(csid & 0x3F);
    // Type-0 message header.
    out.push(((timestamp >> 16) & 0xFF) as u8);
    out.push(((timestamp >> 8) & 0xFF) as u8);
    out.push((timestamp & 0xFF) as u8);
    let len = payload.len() as u32;
    out.push(((len >> 16) & 0xFF) as u8);
    out.push(((len >> 8) & 0xFF) as u8);
    out.push((len & 0xFF) as u8);
    out.push(msg_type);
    out.extend_from_slice(&msg_stream_id.to_le_bytes()); // message stream id is little-endian

    let cs = chunk_size.max(1);
    let mut off = 0usize;
    let mut first = true;
    while off < payload.len() {
        if !first {
            out.push(0xC0 | (csid & 0x3F)); // fmt = 3 continuation
        }
        let end = (off + cs).min(payload.len());
        out.extend_from_slice(&payload[off..end]);
        off = end;
        first = false;
    }
    out
}

/// Wrap an FLV video tag body as an RTMP video message (type 9, stream id given).
pub fn video_message(stream_id: u32, timestamp: u32, flv_video_body: &[u8], chunk_size: usize) -> Vec<u8> {
    chunk_message(6, timestamp, 0x09, stream_id, flv_video_body, chunk_size)
}
/// Wrap an FLV audio tag body as an RTMP audio message (type 8).
pub fn audio_message(stream_id: u32, timestamp: u32, flv_audio_body: &[u8], chunk_size: usize) -> Vec<u8> {
    chunk_message(4, timestamp, 0x08, stream_id, flv_audio_body, chunk_size)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn handshake_c0c1_shape() {
        let h = handshake_c0c1(0);
        assert_eq!(h.len(), 1 + 1536, "C0(1) + C1(1536)");
        assert_eq!(h[0], 0x03, "RTMP version 3");
        assert_eq!(&h[1..5], &[0, 0, 0, 0], "timestamp 0");
        assert_eq!(&h[5..9], &[0, 0, 0, 0], "zero field");
        // C2 echoes S1.
        let s1 = vec![7u8; 1536];
        assert_eq!(handshake_c2(&s1), s1);
    }

    #[test]
    fn amf0_connect_shape() {
        let c = amf0_connect("live", "rtmp://host/live");
        assert_eq!(c[0], 0x02, "string marker");
        assert_eq!(&c[1..3], &[0, 7], "\"connect\".len() = 7");
        assert_eq!(&c[3..10], b"connect");
        assert_eq!(c[10], 0x00, "number marker (transaction id)");
        assert_eq!(&c[11..19], &1.0f64.to_be_bytes(), "txn id = 1.0");
        assert_eq!(c[19], 0x03, "object marker");
        assert!(c.windows(3).any(|w| w == b"app"), "has app key");
        assert!(c.windows(5).any(|w| w == b"tcUrl"), "has tcUrl key");
        assert_eq!(&c[c.len() - 3..], &[0, 0, 0x09], "AMF0 object end");
    }

    #[test]
    fn publish_command_shape() {
        let p = amf0_publish(4.0, "my-stream");
        assert_eq!(&p[3..10], b"publish");
        // ends with the "live" string.
        assert!(p.windows(4).any(|w| w == b"live"));
        assert!(p.windows(9).any(|w| w == b"my-stream"));
    }

    #[test]
    fn chunk_framing_splits_and_continues() {
        let payload = vec![0xAAu8; 300];
        let framed = chunk_message(6, 0, 0x09, 1, &payload, 128);
        assert_eq!(framed[0], 6, "fmt 0, csid 6");
        let len = ((framed[4] as u32) << 16) | ((framed[5] as u32) << 8) | (framed[6] as u32);
        assert_eq!(len, 300, "message length field");
        assert_eq!(framed[7], 0x09, "message type (video)");
        assert_eq!(&framed[8..12], &1u32.to_le_bytes(), "stream id little-endian");
        // 12 header + 300 payload + 2 continuation basic headers (300 → 128|128|44).
        assert_eq!(framed.len(), 12 + 300 + 2);
        assert_eq!(framed[12 + 128], 0xC0 | 6, "fmt 3 continuation header");
    }

    #[test]
    fn handles_a_4k_iframe_payload() {
        // A 4K H.264 keyframe is multi-MB; it must split into many chunks cleanly.
        let frame = vec![0x42u8; 2_000_000]; // ~2 MB, realistic 4K I-frame
        let cs = 4096;
        let framed = video_message(1, 0, &frame, cs);
        // Walk continuation headers: 1 type-0 (12B) header + ceil(2MB/cs)-1 type-3 (1B) headers.
        let n_chunks = frame.len().div_ceil(cs);
        let expected = 12 + frame.len() + (n_chunks - 1);
        assert_eq!(framed.len(), expected, "4K frame chunking accounts for every byte");
        let len = ((framed[4] as u32) << 16) | ((framed[5] as u32) << 8) | (framed[6] as u32);
        assert_eq!(len as usize, frame.len(), "24-bit length field carries the 2 MB frame");
        assert_eq!(framed[12 + cs], 0xC0 | 6, "first continuation is fmt-3");
    }

    #[test]
    fn set_chunk_size_is_control_message() {
        let m = set_chunk_size(4096);
        assert_eq!(m[0], 2, "control on chunk stream 2");
        assert_eq!(m[7], 0x01, "Set Chunk Size message type");
        assert_eq!(&m[12..16], &4096u32.to_be_bytes());
    }
}
